  ) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: true,
    };
  },
  [BlockCardTypes.CLEAR](): State {
    return initialState;
  },
});

type BlockCardActions = {
  blockCardRequest: (
    _isTemporary: boolean,
    _lastFourNumbers: string,
    _blockCode: string,
    _callBack?: BlockCardCallback,
  ) => Action;
  blockCardSuccess: (_data: { data: BlockCardResponse }) => Action;
  blockCardFailed: (_data: { data: BlockCardResponse }) => Action;
  blockCardClear: () => Action;
};

export const blockCardActions: BlockCardActions = {
  blockCardRequest: (
    isTemporary: boolean,
    lastFourNumbers: string,
    blockCode: string,
    callBack?: BlockCardCallback,
  ) => ({
    type: BlockCardTypes.REQUEST,
    isTemporary,
    lastFourNumbers,
    blockCode,
    callBack,
  }),
  blockCardSuccess: (data: { data: BlockCardResponse }) => ({
    type: BlockCardTypes.SUCCESS,
    data,
  }),
  blockCardFailed: (data: { data: BlockCardResponse }) => ({
    type: BlockCardTypes.FAILED,
    data,
  }),
  blockCardClear: () => ({
    type: BlockCardTypes.CLEAR,
  }),
};

export default blockCardReducer;

