import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export const CardTrackingTypes = {
  REQUEST_CARD_TRACKING: '@cardTracking/REQUEST_CARD_TRACKING',
  SUCCESS_CARD_TRACKING: '@cardTracking/SUCCESS_CARD_TRACKING',
  FAILED_CARD_TRACKING: '@cardTracking/FAILED_CARD_TRACKING',
  CLEAN: '@cardTracking/CLEAN',
};

type CardData = {
  Conta: string;
  VlLimiteCreditoDisponivel: number;
  DiaVencimento: string;
  NomePortador: string;
  NumeroCartao: string;
  SequenciaCartao: number;
  Bandeira: string;
  Titular: boolean;
  JwtCartao: string;
  Bloqueio: boolean;
  CodigoBloqueio: number;
  CartaoCriptografado: string;
  Virtual: boolean;
  ValidadeCartao: string;
  Logo: string;
};

type DeliveryStatus =
  | 'REQUESTED'
  | 'IN_TRANSIT'
  | 'DELIVERED'
  | 'RETURNED_TO_SENDER'
  | 'DESTROYED'
  | 'UNKNOWN'
  | 'HELD_AT_FACILITY'
  | 'DELIVERY_EXCEPTION'
  | 'READY_FOR_PICKUP';

type _TimelineType = 'success' | 'disabled' | 'alert' | 'error' | 'info';

interface TrackingEvent {
  status: DeliveryStatus;
  timestamp: string;
  summary: string;
  details: string;
  trackingDetails?: {
    courier: string;
    trackingNumber: string;
  };
}

export interface CardDelivery {
  card: CardData;
  deliveryAddress: string;
  estimatedDeliveryDate: Date;
  trackingHistory: TrackingEvent[];
}

export interface CardTrackingResponse {
  code: number;
  message: string;
  data: {
    trackedCards: CardDelivery[];
  };
}

export interface CardTrackingReducerProps {
  isLoading: boolean;
  isError: boolean;
  data: CardDelivery[] | undefined;
}

interface CardTrackingActions {
  requestCardTracking: () => {
    type: string;
  };
  successCardTracking: (_data: CardDelivery[]) => {
    type: string;
    data: CardDelivery[];
  };
  failedCardTracking: () => Action;
  clean: () => Action;
}

const initialState: CardTrackingReducerProps = {
  isLoading: false,
  isError: false,
  data: undefined,
};

type State = CardTrackingReducerProps;

const cardTrackingReducer = createReducer(initialState, {
  [CardTrackingTypes.REQUEST_CARD_TRACKING](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [CardTrackingTypes.SUCCESS_CARD_TRACKING]: (
    state: State,
    action: { data: CardDelivery[] },
  ): State => {
    return {
      ...state,
      isLoading: false,
      isError: false,
      data: action.data,
    };
  },
  [CardTrackingTypes.FAILED_CARD_TRACKING](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
      data: undefined,
    };
  },
  [CardTrackingTypes.CLEAN](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      data: undefined,
    };
  },
});

export const cardTrackingActions: CardTrackingActions = {
  requestCardTracking: () => ({
    type: CardTrackingTypes.REQUEST_CARD_TRACKING,
  }),
  successCardTracking: (data: CardDelivery[]) => ({
    type: CardTrackingTypes.SUCCESS_CARD_TRACKING,
    data,
  }),
  failedCardTracking: () => ({
    type: CardTrackingTypes.FAILED_CARD_TRACKING,
  }),
  clean: () => ({
    type: CardTrackingTypes.CLEAN,
  }),
};

export default cardTrackingReducer;

