import type { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

import { Contents } from '../../screens/Benefits/Models';

interface _DispatchTypes {
  REQUEST: string;
  SUCESS: string;
  FAILED: string;
  CLEAR: string;
}

export enum ContentTypes {
  CLEAR = 'contents/clear',
  SUCESS = 'contents/sucess',
  FAILED = 'contents/failed',
  REQUEST = 'contents/request',
}

export interface ContentReducerProps {
  data: Contents[];
  isError: boolean;
  isLoading: boolean;
}

const initialState: ContentReducerProps = {
  data: [],
  isError: false,
  isLoading: false,
};

const contentsReducer = createReducer(initialState, {
  [ContentTypes.REQUEST](state: ContentReducerProps) {
    return { ...state, isLoading: true, isError: false };
  },
  [ContentTypes.SUCESS](state: ContentReducerProps, data: Contents[]) {
    return { ...state, ...data, isLoading: false, isError: false };
  },
  [ContentTypes.FAILED](state: ContentReducerProps) {
    return { ...state, isLoading: false, isError: true };
  },
  [ContentTypes.CLEAR]() {
    return initialState;
  },
});

type Actions = {
  fail: () => Action;
  clearContents: () => Action;
  requestContents: () => Action;
  success: (_data: Contents[]) => Action;
};

export const ContentActions: Actions = {
  requestContents: () => ({
    type: ContentTypes.REQUEST,
  }),
  success: (data: Contents[]) => ({
    type: ContentTypes.SUCESS,
    data,
  }),
  fail: () => ({
    type: ContentTypes.FAILED,
  }),
  clearContents: () => ({
    type: ContentTypes.CLEAR,
  }),
};

export default contentsReducer;

